parameters.jsCode:
// ── Parse AI lead summary + check calendar + generate timezone-aware slots ──

const agentOut = $('AI Agent: Score Lead').first().json;
const raw = $('Receive Form (Webhook)').first().json;

// n8n webhook node puts body fields at top-level AND keeps a 'body' object.
const form = (raw.firstName || raw.email) ? raw : (raw.body || raw);

const firstName   = String(form.firstName   || '').trim();
const lastName    = String(form.lastName    || '').trim();
const email       = String(form.email       || '').trim();
const phone       = String(form.phone       || '').trim();
const company     = String(form.company     || '').trim();
const revenue     = String(form.revenue     || '').trim();
const service     = String(form.service     || '').trim();
const timeline    = String(form.timeline    || '').trim();
const message     = String(form.message     || '').trim();
const country     = String(form.country     || '').trim();
const submittedAt = String(form.submittedAt || new Date().toISOString());

// Extract lead summary from agent output
const leadSummary = agentOut.output || agentOut.text || agentOut.message?.content ||
  '⚠️ AI scoring unavailable — review manually.';

// ── Country → IANA timezone lookup ──
const COUNTRY_TZ = {
  'usa': 'America/New_York', 'us': 'America/New_York',
  'united states': 'America/New_York', 'united states of america': 'America/New_York',
  'usa - east': 'America/New_York', 'usa - eastern': 'America/New_York',
  'usa - central': 'America/Chicago',
  'usa - mountain': 'America/Denver',
  'usa - west': 'America/Los_Angeles', 'usa - pacific': 'America/Los_Angeles',
  'uk': 'Europe/London', 'united kingdom': 'Europe/London',
  'gb': 'Europe/London', 'england': 'Europe/London',
  'canada': 'America/Toronto', 'canada - west': 'America/Vancouver',
  'australia': 'Australia/Sydney', 'australia - perth': 'Australia/Perth',
  'uae': 'Asia/Dubai', 'dubai': 'Asia/Dubai',
  'singapore': 'Asia/Singapore', 'germany': 'Europe/Berlin',
  'france': 'Europe/Paris', 'netherlands': 'Europe/Amsterdam',
  'india': 'Asia/Kolkata', 'japan': 'Asia/Tokyo',
  'china': 'Asia/Shanghai', 'hong kong': 'Asia/Hong_Kong',
  'brazil': 'America/Sao_Paulo', 'mexico': 'America/Mexico_City',
  'south africa': 'Africa/Johannesburg', 'kenya': 'Africa/Nairobi',
  'israel': 'Asia/Jerusalem', 'turkey': 'Europe/Istanbul',
  'sweden': 'Europe/Stockholm', 'norway': 'Europe/Oslo',
  'new zealand': 'Pacific/Auckland', 'malaysia': 'Asia/Kuala_Lumpur',
  'indonesia': 'Asia/Jakarta', 'philippines': 'Asia/Manila',
  'thailand': 'Asia/Bangkok', 'pakistan': 'Asia/Karachi',
  'bangladesh': 'Asia/Dhaka', 'sri lanka': 'Asia/Colombo'
};

const clientTz = COUNTRY_TZ[country.toLowerCase()] || null;

function formatInTz(utcMs, tz) {
  try {
    return new Intl.DateTimeFormat('en-US', {
      timeZone: tz, weekday: 'long', month: 'short', day: 'numeric',
      hour: 'numeric', minute: '2-digit', hour12: true, timeZoneName: 'short'
    }).format(new Date(utcMs));
  } catch(e) { return ''; }
}

// ── Calendar busy times ($input = Check Calendar Availability output) ──
// alwaysOutputData:true ensures this runs even when calendar has 0 events.
const calItems = $input.all();
const busyTimes = calItems
  .map(item => item.json)
  .filter(e => e && e.start)
  .map(e => ({
    start: new Date(e.start.dateTime || (e.start.date + 'T00:00:00')).getTime(),
    end:   new Date(e.end.dateTime   || (e.end.date   + 'T23:59:59')).getTime()
  }))
  .filter(b => !isNaN(b.start) && !isNaN(b.end));

function isAvailable(slotStartMs, slotEndMs) {
  return !busyTimes.some(b => slotStartMs < b.end && slotEndMs > b.start);
}

// ── Time slot generation (Mon–Fri IST, skip busy calendar events) ──
const IST = 19800000; // UTC+5:30 in ms

function istLabel(utcMs) {
  const d = new Date(utcMs + IST);
  const DAYS = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const MON  = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const h = d.getUTCHours(), m = d.getUTCMinutes();
  const ap = h >= 12 ? 'PM' : 'AM';
  const h12 = h % 12 || 12;
  return DAYS[d.getUTCDay()] + ', ' + d.getUTCDate() + ' ' + MON[d.getUTCMonth()] +
         ' at ' + h12 + ':' + String(m).padStart(2,'0') + ' ' + ap + ' IST';
}

const PREFS = [{h:10,m:30},{h:12,m:0},{h:15,m:0},{h:17,m:0}];
const now = new Date();
const slots = [];
let dayOffset = 1;

while (slots.length < 5 && dayOffset <= 21) {
  const baseUTC = new Date(now.getTime() + dayOffset * 86400000);
  const baseIST = new Date(baseUTC.getTime() + IST);
  const dow = baseIST.getUTCDay();
  if (dow >= 1 && dow <= 5) {
    for (const p of PREFS) {
      if (slots.length >= 5) break;
      const utcMs = Date.UTC(
        baseIST.getUTCFullYear(), baseIST.getUTCMonth(), baseIST.getUTCDate(),
        p.h, p.m, 0, 0
      ) - IST;
      const endMs = utcMs + 1800000;

      if (!isAvailable(utcMs, endMs)) continue;

      const base = istLabel(utcMs);
      let labelClient = base;
      if (clientTz) {
        const localStr = formatInTz(utcMs, clientTz);
        if (localStr) labelClient = localStr + '  (' + base + ')';
      }

      slots.push({
        index:       slots.length + 1,
        label:       base,
        labelClient: labelClient,
        startISO:    new Date(utcMs).toISOString(),
        endISO:      new Date(endMs).toISOString()
      });
    }
  }
  dayOffset++;
}

const submissionId = 'NXF-' + Date.now();
const slotsJSON = JSON.stringify(slots);
const slotsText = slots.map(s => 'Option ' + s.index + ': ' + s.label).join('\n');
const slotsHTML = slots.map(s =>
  '<p style="margin:6px 0;"><strong>Option ' + s.index + ':</strong> ' + s.labelClient + '</p>'
).join('');

return [{
  json: {
    firstName, lastName, email, phone, company, revenue, service,
    timeline, message, country, submittedAt, leadSummary, submissionId,
    slotsJSON, slotsText, slotsHTML,
    clientTz: clientTz || '',
    calendarChecked: busyTimes.length > 0
  }
}];

